from typing import List, Optional

def buildTree(inorder: List[int], postorder: List[int]) -> Optional[object]:
    index_map = {val: i for i, val in enumerate(inorder)}

    def helper(in_start: int, in_end: int, post_start: int, post_end: int) -> Optional[object]:
        if in_start > in_end or post_start > post_end:
            return None
        root_val = postorder[post_end]
        root = type('TreeNode', (), {'val': root_val, 'left': None, 'right': None})()
        root_idx = index_map[root_val]
        left_size = root_idx - in_start
        root.left = helper(in_start, root_idx - 1, post_start, post_start + left_size - 1)
        root.right = helper(root_idx + 1, in_end, post_start + left_size, post_end - 1)
        return root

    return helper(0, len(inorder) - 1, 0, len(postorder) - 1)
